 'scripts/android/headless-emulator-test.sh':('$(dirname "${BASH_SOURCE[0]}")/..','$(dirname "${BASH_SOURCE[0]}")/../..'),
 'scripts/android/overnight-ui-monkey.sh':('$(dirname "${BASH_SOURCE[0]}")/..','$(dirname "${BASH_SOURCE[0]}")/../..'),
